# Integrating Claude into Your Next.js App

Here's a straightforward architecture that gets you streaming AI responses with minimal complexity.

## Architecture Overview

```
┌─────────────┐     ┌──────────────────┐     ┌─────────────┐
│   React UI  │────▶│  Next.js Route   │────▶│  Claude API  │
│  (streaming │◀────│  Handler (API)   │◀────│  (streaming) │
│   display)  │ SSE │                  │ SSE │              │
└─────────────┘     └──────────────────┘     └─────────────┘
                           │
                    ┌──────┴──────┐
                    │  Your DB /  │
                    │  Data Layer │
                    └─────────────┘
```

The key idea: your Next.js API route fetches the user's data, injects it into the prompt as context, and streams Claude's response back to the browser.

## 1. Install the SDK

```bash
npm install @anthropic-ai/sdk
```

## 2. API Route (Server-Side Streaming)

```typescript
// app/api/ask/route.ts
import Anthropic from "@anthropic-ai/sdk";
import { NextRequest } from "next/server";
import { getUserData } from "@/lib/data"; // your data-fetching layer

const client = new Anthropic(); // reads ANTHROPIC_API_KEY from env

export async function POST(req: NextRequest) {
  const { question, userId } = await req.json();

  // Step 1: Fetch the user's relevant data
  const userData = await getUserData(userId);

  // Step 2: Stream Claude's response
  const stream = await client.messages.stream({
    model: "claude-sonnet-4-5-20250929",
    max_tokens: 4096,
    system: `You are a helpful assistant that answers questions about the user's data.
Be concise, accurate, and cite specific numbers when relevant.

Here is the user's data:
${JSON.stringify(userData, null, 2)}`,
    messages: [{ role: "user", content: question }],
  });

  // Step 3: Convert to a ReadableStream for the browser
  const encoder = new TextEncoder();
  const readable = new ReadableStream({
    async start(controller) {
      stream.on("text", (text) => {
        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ text })}\n\n`));
      });

      stream.on("end", () => {
        controller.enqueue(encoder.encode("data: [DONE]\n\n"));
        controller.close();
      });

      stream.on("error", (err) => {
        console.error("Stream error:", err);
        controller.error(err);
      });
    },
  });

  return new Response(readable, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}
```

## 3. React Hook for Consuming the Stream

```typescript
// hooks/useAskAI.ts
import { useState, useCallback } from "react";

export function useAskAI() {
  const [answer, setAnswer] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const ask = useCallback(async (question: string, userId: string) => {
    setAnswer("");
    setIsLoading(true);

    try {
      const res = await fetch("/api/ask", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ question, userId }),
      });

      if (!res.ok) throw new Error(`HTTP ${res.status}`);

      const reader = res.body!.getReader();
      const decoder = new TextDecoder();

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split("\n").filter((l) => l.startsWith("data: "));

        for (const line of lines) {
          const data = line.slice(6); // strip "data: "
          if (data === "[DONE]") break;

          try {
            const { text } = JSON.parse(data);
            setAnswer((prev) => prev + text);
          } catch {
            // skip malformed chunks
          }
        }
      }
    } catch (err) {
      console.error(err);
      setAnswer("Sorry, something went wrong. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  return { answer, isLoading, ask };
}
```

